#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const LL N = 1e5+5;
LL n,m,Q,ans[N];
struct node{
    LL opt,id,x,y,k;
}q[N],q1[N],q2[N];
struct SegTree{
    LL sum,tag;
    bool ling;
}tr[N<<2];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL ls(LL u){return (u<<1);}
LL rs(LL u){return (u<<1|1);}
void push_up(LL u){
    tr[u].sum=tr[ls(u)].sum+tr[rs(u)].sum;return;
}
void push_down(LL u,LL l,LL r){
    if(tr[u].ling){
        tr[u].ling=0;
        tr[ls(u)].sum=0,tr[ls(u)].tag=0;
        tr[rs(u)].sum=0,tr[rs(u)].tag=0;
        tr[ls(u)].ling=1,tr[rs(u)].ling=1;
    }if(tr[u].tag){
        LL mid=(l+r)>>1;
        tr[ls(u)].sum+=(mid-l+1)*tr[u].tag;
        tr[rs(u)].sum+=(r-mid)*tr[u].tag;
        tr[ls(u)].tag+=tr[u].tag,tr[rs(u)].tag+=tr[u].tag;
        tr[u].tag=0;
    }return;
}
void change(LL u,LL l,LL r,LL L,LL R,LL k){
    if(r<L||R<l)return;
    if(L<=l&&r<=R){tr[u].sum+=(r-l+1)*k,tr[u].tag+=k;return;}
    LL mid=(l+r)>>1;push_down(u,l,r);
    if(L<=mid)change(ls(u),l,mid,L,R,k);
    if(mid<R)change(rs(u),mid+1,r,L,R,k);
    push_up(u);return;
}
LL ask(LL u,LL l,LL r,LL L,LL R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return tr[u].sum;
    LL mid=(l+r)>>1,res=0;
    push_down(u,l,r);
    if(L<=mid)res+=ask(ls(u),l,mid,L,R);
    if(mid<R)res+=ask(rs(u),mid+1,r,L,R);
    return res;
}
void solve(LL l,LL r,LL L,LL R){
    if(L>R)return;
    if(l==r){
        for(LL i=L;i<=R;i++)
            if(q[i].opt==2)ans[q[i].id]=l;
        return;
    }
    LL mid=(l+r)>>1,p1=0,p2=0;
    tr[1]={0,0,1};
    bool fl1=0,fl2=0;
    for(LL i=L;i<=R;i++)
        if(q[i].opt==1)
            if(q[i].k>mid)
                change(1,1,n,q[i].x,q[i].y,1),q2[++p2]=q[i];
            else q1[++p1]=q[i];
        else{
            LL cnt=ask(1,1,n,q[i].x,q[i].y);
            if(cnt>=q[i].k)q2[++p2]=q[i],fl2=1;
            else q[i].k-=cnt,q1[++p1]=q[i],fl1=1;
        }
    for(LL i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(LL i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    if(fl1)solve(l,mid,L,L+p1-1);
    if(fl2)solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read(),Q=0;
    for(LL i=1;i<=m;i++){
        LL opt=read(),l=read(),r=read(),k=read();
        q[i]={opt,(opt==2?++Q:0),l,r,k};
    }
    solve(-n,n,1,m);
    for(LL i=1;i<=Q;i++)cout<<ans[i]<<"\n";
    return 0;
}
